CG-colorfulFolder.general:
.CG-colorfulFolder .nav-files-container > div > .nav-folder {
transition: background-color 0.4s;
background-color: rgba(var(--color--bg-rainbow-folder), 0.3);
margin-bottom: 5px;
padding: 0px 10px 0px 27px;
border-radius: 5px;
border-image-slice: 1;
border-top: 1px solid;
border-image-source: linear-gradient(to right, transparent, rgb(var(--color--bg-rainbow-folder)), transparent);
border-bottom: 1px solid;
}

.CG-colorfulFolder:not(.CG-scifiFolder) .nav-files-container > div > .nav-folder {
clip-path: polygon(
    0% 0%, 
    calc(100% - 17px) 0%, 
    100% 17px, 
    100% 100%, 
    17px 100%, 
    0% calc(100% - 17px)
  );
}

CG-FileTreeShade1.general:
.CG-FileTreeShade1 .tree-item-self {
background: var(--background-settings-alt);
padding: 10px 10px 10px 5px;
margin-bottom: 5px;
clip-path: polygon(0% 0%, calc(100% - 17px) 0%, 100% 17px, 100% 100%, 17px 100%, 0% calc(100% - 17px));
z-index: 0;
padding-inline-start: 10px;
}
